// TODO: Implement problem eight using sequential streams
public static Map<Long, Double> problemEightSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
    // Create mapping: tier-0 customer IDs -> sales utilization rate
    // Utilization rate = total amount paid / total full price available
    Map<Long, Double> result = new HashMap<>();

    Map<Long, Double> amountPaid = orderRepo.findAll().stream()
        .filter(order -> order.getCustomer().getTier() == 0)
        .collect(Collectors.groupingBy(
            order -> order.getCustomer().getId(),
            Collectors.flatMapping(
                order -> order.getProducts().stream(),
                Collectors.summingDouble(Product::getSalePrice)
            )
        ));

    Map<Long, Double> fullPriceAvailable = orderRepo.findAll().stream()
        .filter(order -> order.getCustomer().getTier() == 0)
        .collect(Collectors.groupingBy(
            order -> order.getCustomer().getId(),
            Collectors.flatMapping(
                order -> order.getProducts().stream(),
                Collectors.summingDouble(Product::getFullPrice)
            )
        ));

    for (Long customerId : amountPaid.keySet()) {
        result.put(customerId, amountPaid.get(customerId) / fullPriceAvailable.get(customerId));
    }

    return result;
}

