public static Double problemFourSeq(CustomerRepo customerRepo, OrderRepo orderRepo, ProductRepo productRepo) {
    // Calculate total discount for March orders
    // Discount = fullPrice - bestPrice (where bestPrice considers sale price and customer tier)
    return orderRepo.findAll().stream()
        .filter(order -> order.getOrderDate() != null &&
                       order.getOrderDate().getMonth() == java.time.Month.MARCH)
        .flatMap(order -> order.getProducts().stream().map(product -> new AbstractMap.SimpleEntry<>(order.getCustomer(), product)))
        .mapToDouble(entry -> {
            Customer customer = entry.getKey();
            Product product = entry.getValue();

            double bestPrice = product.getFullPrice();

            // Check sale price
            if (product.getSalePrice() != null && product.getSalePrice() < bestPrice) {
                bestPrice = product.getSalePrice();
            }

            // Check tier prices
            if (customer.getTier() == 1 && product.getTierOnePrice() != null && product.getTierOnePrice() < bestPrice) {
                bestPrice = product.getTierOnePrice();
            } else if (customer.getTier() == 2 && product.getTierTwoPrice() != null && product.getTierTwoPrice() < bestPrice) {
                bestPrice = product.getTierTwoPrice();
            }

            return product.getFullPrice() - bestPrice;
        })
        .sum();
}

